ALTER TABLE reviews ADD COLUMN IF NOT EXISTS orderId INT AFTER customerId;
ALTER TABLE reviews ADD COLUMN IF NOT EXISTS content TEXT AFTER title;
ALTER TABLE reviews ADD COLUMN IF NOT EXISTS helpfulCount INT DEFAULT 0 AFTER isApproved;

-- Add foreign key constraints if they don't exist
ALTER TABLE reviews ADD CONSTRAINT reviews_customer_fk FOREIGN KEY (customerId) REFERENCES users(id) ON DELETE CASCADE;
ALTER TABLE reviews ADD CONSTRAINT reviews_order_fk FOREIGN KEY (orderId) REFERENCES orders(id) ON DELETE CASCADE;

-- Add indexes
ALTER TABLE reviews ADD KEY reviews_customer_idx (customerId);
ALTER TABLE reviews ADD KEY reviews_order_idx (orderId);

